    """Number of index pairs i<j with nums[i] + nums[j] == target."""
    from collections import Counter
    freq = Counter(nums)
    total = 0
    for num, c in freq.items():
        complement = target - num
        if complement > num:
            total += c * freq[complement]
        elif complement == num and c >= 2:
